import Q from "../../../../../../../../../../../subject_repositories/q/q.js";

describe("isNodeFrame filtering in long stack traces", () => {
  it("should filter node.js internal frames from error stacks", async () => {
    Q.longStackSupport = true;

    const deferred = Q.defer();

    // Ensure promise has a stack so makeStackTraceLong will execute
    if (!deferred.promise.stack) {
      deferred.promise.stack = "Error: \n    at createDeferred (app.js:1:1)";
      deferred.promise.stackCounter = 1;
    }

    // Create error with a node.js internal frame in its stack
    const err = new Error("test error");
    err.stack = "Error: test error\n    at myFunction (app.js:5:3)\n    at Module._compile (module.js:456:26)";

    deferred.reject(err);

    let caught: any;
    await deferred.promise.then(null, (e: any) => { caught = e; });

    expect(caught).toBeDefined();
    expect(caught.stack).toBeDefined();
    expect(caught.stack).not.toContain("module.js:");
  });
});
